import fs from 'fs'
import path from 'path'
import { fileURLToPath } from 'url'
import { defaultScene } from './templates/scene.js'
import { defaultHTML } from './templates/html.js'
import { defaultGame } from './templates/game.js'
import { defaultREADME } from './templates/readme.js'
import { defaultMakiConfig } from './templates/makiconfig.js'

const __filename = fileURLToPath(import.meta.url)
const __dirname = path.dirname(__filename)

const PROJECT_FILES = [
    { path: 'scenes/GameScene.js', template: defaultScene },
    { path: 'index.html', template: defaultHTML },
    { path: 'game.js', template: defaultGame },
    { path: 'README.md', template: defaultREADME, isParametrized: true },
    { path: 'maki.config.js', template: defaultMakiConfig },
]

const PROJECT_DIRS = ['scenes', 'assets']

const STATIC_FILES = [
    // lia.png is in assets/sprites/ and gets copied via copyDir
    // default_map.json lives inside assets/maps/ so publicDir covers it
    { src: '../templates/maps/default_map.json', dest: 'assets/maps/default_map.json' },
    { src: '../templates/vite.config.js',        dest: 'vite.config.js' },
]

const ASSETS_SRC = path.resolve(__dirname, '../assets')

function copyDir(src, dest) {
    fs.mkdirSync(dest, { recursive: true })
    for (const entry of fs.readdirSync(src, { withFileTypes: true })) {
        const srcPath = path.join(src, entry.name)
        const destPath = path.join(dest, entry.name)
        if (entry.isDirectory()) {
            copyDir(srcPath, destPath)
        } else {
            fs.copyFileSync(srcPath, destPath)
        }
    }
}

export function create() {
    const gameName = process.argv[3]

    if (!gameName) {
        console.log('Please provide a game name. Example: maki new my-game')
        return
    }

    PROJECT_DIRS.forEach(dir => {
        fs.mkdirSync(`${gameName}/${dir}`, { recursive: true })
    })

    PROJECT_FILES.forEach(file => {
        const content = file.isParametrized ? file.template(gameName) : file.template()
        fs.writeFileSync(`${gameName}/${file.path}`, content)
    })

    // Copy entire assets tree (rooms, bedroom, kitchen, random) first
    copyDir(ASSETS_SRC, path.join(gameName, 'assets'))

    // Copy individual static files (map + vite config)
    STATIC_FILES.forEach(file => {
        const dest = path.join(gameName, file.dest)
        fs.mkdirSync(path.dirname(dest), { recursive: true })
        fs.copyFileSync(
            path.resolve(__dirname, file.src),
            dest
        )
    })

    console.log(`🍣 Maki game "${gameName}" created!`)
    console.log(`   cd ${gameName} && maki dev`)
}
